public class VariableSwap {
    public static void main(String[] args) {
        int a = 10;
        int b = 25;

        System.out.println("Before swap: a = " + a + ", b = " + b);

        // Swap a and b WITHOUT using a third variable

        System.out.println("After swap: a = " + a + ", b = " + b);
    }
}

public class Constants {
    public static void main(String[] args) {
        final double PI = 3.14159;
        final int MAX_USERS = 100;

        System.out.println("PI = " + PI);
        System.out.println("Max users allowed = " + MAX_USERS);

        double radius = 7.0;
        // Calculate and print the area of a circle using PI
        double area; // area = PI * radius * radius
        System.out.println("Area of circle with radius 7: " + area);
    }
}

public class VariableNaming {
    public static void main(String[] args) {
        // Fix these variable declarations - some have invalid names, some have poor names
        int 1stNumber = 10;          // invalid name
        double x = 3.14;             // poor name - rename to 'piValue'
        String my-name = "Alice";   // invalid name
        boolean Flag = true;         // poor name - rename to 'isLoggedIn'

        System.out.println("First number: " + 1stNumber);
        System.out.println("Pi value: " + x);
        System.out.println("Name: " + my-name);
        System.out.println("Logged in: " + Flag);
    }
}
